{
  "kind": "DataVisualizationNode",
  "source": {
    "kind": "HogQLQuery",
    "query": "WITH anon_opens AS (\n    SELECT\n        toDate(timestamp) AS dt,\n        person_id\n    FROM events\n    WHERE event = 'Application Opened'\n      AND position(distinct_id, '-') > 0\n      AND timestamp >= now() - INTERVAL 45 DAY\n      AND {filters}\n    GROUP BY dt, person_id\n),\nlogins AS (\n    SELECT\n        toDate(timestamp) AS dt,\n        person_id\n    FROM events\n    WHERE event = '$identify'\n      AND timestamp >= now() - INTERVAL 45 DAY\n      AND {filters}\n    GROUP BY dt, person_id\n)\nSELECT\n    a.dt AS date,\n    count(DISTINCT a.person_id) AS anon_openers,\n    count(DISTINCT l.person_id) AS logged_in_users,\n    round(count(DISTINCT l.person_id) / count(DISTINCT a.person_id) , 4) AS login_rate\nFROM anon_opens a\nLEFT JOIN logins l ON a.person_id = l.person_id AND a.dt = l.dt\nwhere a.dt>='2026-06-25'\nGROUP BY a.dt\nORDER BY a.dt ASC\nLIMIT 305",
    "filters": {
      "properties": []
    }
  },
