      "native": "select to_date(x.create_time) 日期,x.msg_id pushid,title 标题,content 内容\n\t\t,case jump_type when 1 then '站内地址' when 2 then '其它地址' when 3 then '应用市场' else '未知' end as 跳转方式,count(distinct x.uid) push_uv,count(1) push_pv\n\tfrom dwd_usr_t_lute_market_msglog_di x \n\tjoin dwd_usr_t_lute_market_message_df y on x.msg_id = y.id\n\twhere to_date(x.create_time) >= DATE_SUB(CURDATE(), INTERVAL 21 DAY) -- and y.ds >= '2026-01-01'\n\t  and x.status = 1 --and cast(x.id as string) = '2040837007194732105'\n\tgroup by to_date(x.create_time),x.msg_id,title,content,case jump_type when 1 then '站内地址' when 2 then '其它地址' when 3 then '应用市场' else '未知' end\norder by 日期 desc",
      "lib/type": "mbql.stage/native"
    }
  ]
}

