  "database": 4,
  "stages": [
    {
      "native": "SELECT\n    DATE(dev_create_time)     AS bind_date,\n    model,\n    COUNT(DISTINCT uid)       AS bind_user_cnt\nFROM dwd_app_device_binding_info\nWHERE status = 1\n  AND dev_create_time >= '2026-01-01'\n  [[AND {{model_filter}}]]\nGROUP BY DATE(dev_create_time), model\nORDER BY bind_date, model;\n",
