{
  "lib/type": "mbql/query",
  "database": 4,
  "stages": [
    {
      "native": "SELECT a.uid as 用户ID, bind_date 用户最后绑定日期, country_ad_ch 国家\nFROM\n     (SELECT uid,\n          date(dev_create_time) bind_date,\n          model,\n          country_ad_ch,\n             row_number() OVER (PARTITION BY UID\n                                ORDER BY dev_create_time desc) AS rn\n      FROM dwd_app_device_binding_info\n      WHERE TYPE = 1 and status = 1 and \n      model IN ('M9', 'M5P0', 'Air1','M10') and country_ad_ch in ('美国', '加拿大')\n      ) a\n   WHERE a.rn = 1 and bind_date >= {{start_date}} and bind_date <= {{end_date}} and country_ad_ch IN ({{country}})\n   limit 20000",
      "lib/type": "mbql.stage/native",
      "template-tags": {
        "start_date": {
          "id": "6467cf43-06a1-45c7-9f7a-eb53cb089883",
          "display-name": "绑定日期开始时间",
          "type": "date",
          "name": "start_date",
          "default": "2026-04-27"
        },
        "end_date": {
          "type": "date",
          "display-name": "绑定日期结束时间",
          "name": "end_date",
          "id": "100654e8-63ef-4eb1-9efb-82e4b2c0f0be",
          "default": "2026-04-27"
        },
        "country": {
          "display-name": "国家",
          "id": "4658660f-6f4d-4b87-bfb4-adb284533884",
          "name": "country",
          "type": "text",
          "default": [
            "美国"
          ]
        }
      }
    }
  ]
}

