{
  "lib/type": "mbql/query",
  "database": 4,
  "stages": [
    {
      "lib/type": "mbql.stage/native",
      "native": "with log_info as (\nselect\n       count(case when eventname = 'ForYou_Featured_pageview' then uid end) feature_pv,\n       count(distinct case when eventname = 'ForYou_Featured_pageview' then uid end) feature_uv,\n       sum(distinct case when eventname = 'ForYou_Featured_pageleave' then duration else 0 end) feature_duration,\n       count(distinct case when eventname = 'ForYou_Featured_card_click' then uid end) feature_card_uv,\n       count(distinct case when eventname = 'ForYou_Featured_more_click' then uid end) feature_more_uv,\n       \n       count(case when eventname = 'ForYou_All_Featured_pageview' then uid end) feature_all_pv,\n       count(distinct case when eventname = 'ForYou_All_Featured_pageview' then uid end) feature_all_uv,\n       sum(distinct case when eventname = 'ForYou_All_Featured_pageleave' then duration else 0 end) feature_all_duration\nfrom dwd_tp_foryou_log_di where {{dt}}\n)\nselect \n\t\tcase when feature_uv = 0 then 0 else feature_pv / feature_uv end '【Feature】模块人均访问次数', \n\t\tcase when feature_duration = 0 then 0 else feature_uv / feature_duration end '【Feature】模块人均访问时长', \n\t\tcase when feature_uv = 0 then 0 else feature_card_uv / feature_uv end '【Feature】模块帖子点击曝光比',\n\t\tcase when feature_uv = 0 then 0 else feature_more_uv / feature_uv end '【More】按钮点击曝光比',\n\t\tcase when feature_all_uv = 0 then 0 else feature_all_pv / feature_all_uv end '【All Feature】页面人均访问次数', \n\t\tcase when feature_all_duration = 0 then 0 else feature_all_uv / feature_all_duration end '【All Feature】页面人均访问时长'\n\t\t\nfrom log_info",
      "template-tags": {
        "dt": {
          "widget-type": "date/range",
