      "native": "SELECT\n    evt_dt              AS 日期,\n    SUM(new_users)      AS 新增用户,\n    SUM(new_devices)    AS 新增设备\nFROM lute_app_dw.dws_pump_daily_df\nWHERE evt_dt >= '2026-05-01' AND evt_dt<=CURRENT_DATE\nGROUP BY evt_dt\nORDER BY evt_dt"
    }
  ]
}

{
  "lib/type": "mbql/query",
  "database": 4,
  "stages": [
    {
      "native": "SELECT\n    local_hour                                                 AS 时段_小时,\n    COUNT(DISTINCT useSessionId)                               AS 会话次数,\n    ROUND(COUNT(DISTINCT useSessionId)\n        / SUM(COUNT(DISTINCT useSessionId)) OVER() * 100, 2) AS 占比_pct\nFROM lute_app_dw.dws_pump_session_df\nWHERE evt_dt >='2026-05-01' AND evt_dt<=CURRENT_DATE\n  AND local_hour IS NOT NULL\nGROUP BY local_hour\nORDER BY local_hour",
      "lib/type": "mbql.stage/native"
    }
  ]
}

{
  "lib/type": "mbql/query",
  "database": 4,
  "stages": [
    {
      "lib/type": "mbql.stage/native",
      "native": "SELECT\n    ROUND(AVG(d1_user_ret) * 100, 1)    AS 区间平均D1用户留存率_pct,\n    ROUND(AVG(d7_user_ret) * 100, 1)    AS 区间平均D7用户留存率_pct,\n    ROUND(AVG(d1_device_ret) * 100, 1)  AS 区间平均D1设备留存率_pct,\n    ROUND(AVG(d7_device_ret) * 100, 1)  AS 区间平均D7设备留存率_pct,\n    ROUND(MAX(CASE WHEN base_dt = (SELECT MAX(base_dt) FROM lute_app_dw.dws_pump_retention_di WHERE deviceCode = 'ALL') THEN d1_user_ret END) * 100, 1) AS 最新D1用户留存率_pct,\n    ROUND(MAX(CASE WHEN base_dt = (SELECT MAX(base_dt) FROM lute_app_dw.dws_pump_retention_di WHERE deviceCode = 'ALL') THEN d7_user_ret END) * 100, 1) AS 最新D7用户留存率_pct\nFROM lute_app_dw.dws_pump_retention_di\nWHERE deviceCode = 'ALL'\n  AND base_dt BETWEEN '2026-05-01' AND '2027-05-31'"
    }
  ]
}

