{
  "lib/type": "mbql/query",
  "database": 4,
  "stages": [
    {
      "lib/type": "mbql.stage/native",
      "native": "SELECT\n    dt,\n    -- 统计当天总访问次数 (PV)\n    COUNT(*) AS PV,\n    -- 统计当天独立访问用户数 (UV)\n    COUNT(DISTINCT uid) AS UV,\n    -- 统计当天平均停留时长（单位：秒，原始字段为毫秒）\n    ROUND(AVG(CAST(get_json_string(content, '$.pageStayTime') AS BIGINT)) / 1000, 2) AS '平均停留时长'\nFROM dwd_tp_app_log_di\nWHERE dt >= date_sub(current_date(), INTERVAL 14 DAY) AND dt < current_date()\n  AND data_source = 'EC'\n  AND get_json_string(content, '$.elementId') = '34000001'\n  AND get_json_string(content, '$.extraData.device_model') IN({{device_model}})\nGROUP BY dt\nORDER BY dt\n",
      "template-tags": {
        "device_model": {
          "name": "device_model",
          "display-name": "设备类型",
          "id": "cc31c7e5-9c78-4789-8b53-91d1ff06c45e",
          "type": "text",
          "default": [
            "M9",
            "T3",
            "Air1",
            "BM04",
            "BM08",
            "M5",
            "M5P0",
            "T31",
            "V3",
            "V300",
            "W1",
            "WN02",
            "WN05"
          ]
        }
      }
    }
  ]
}

