{
  "lib/type": "mbql/query",
  "database": 4,
  "stages": [
    {
      "native": "SELECT\n    to_date(busi_date) AS 日期,\n    SUM(app_day_user_cn) AS APP用户日活,\n    SUM(app_day_breast_pump_user_cn) AS 绑定吸奶器用户日活,\n    SUM(app_day_bind_not_breast_pump_user_cn) AS 绑定非吸奶器用户日活,\n    SUM(app_day_not_bind_user_cn) AS 未绑定设备用户日活\nFROM ads_app_device_act_aggr_df\nWHERE to_date(busi_date) >= '2025-01-01'\nGROUP BY to_date(busi_date)\nORDER BY 日期 desc;",
      "lib/type": "mbql.stage/native"
    }
  ]
}

{
